import { useState, useRef, useEffect, useCallback } from "react";
import ReactMarkdown from "react-markdown";
import { v4 as uuidv4 } from "uuid";
import "./App.css";

const BACKEND_URL = process.env.REACT_APP_BACKEND_URL || "http://localhost:5000";
const CONVERSATION_ID = uuidv4(); // unique ID per session

const SUGGESTIONS = [
  "Explain React hooks simply",
  "Write a Python hello world",
  "What is REST API?",
  "Tips to learn coding faster",
];

function App() {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef(null);
  const textareaRef = useRef(null);

  // Auto-scroll to bottom on new messages
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  // Auto-resize textarea as user types
  const handleInputChange = (e) => {
    setInput(e.target.value);
    const ta = textareaRef.current;
    ta.style.height = "auto";
    ta.style.height = Math.min(ta.scrollHeight, 150) + "px";
  };

  const sendMessage = useCallback(
    async (text) => {
      const trimmed = (text || input).trim();
      if (!trimmed || isLoading) return;

      setInput("");
      if (textareaRef.current) textareaRef.current.style.height = "auto";

      // Add user message immediately
      const userMsg = { id: uuidv4(), role: "user", content: trimmed };
      setMessages((prev) => [...prev, userMsg]);
      setIsLoading(true);

      // Add empty assistant message that we'll stream into
      const assistantId = uuidv4();
      setMessages((prev) => [
        ...prev,
        { id: assistantId, role: "assistant", content: "" },
      ]);

      try {
        const res = await fetch(`${BACKEND_URL}/api/chat`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            message: trimmed,
            conversationId: CONVERSATION_ID,
          }),
        });

        if (!res.ok) throw new Error(`Server error: ${res.status}`);

        // Read the SSE stream
        const reader = res.body.getReader();
        const decoder = new TextDecoder();
        let buffer = "";

        while (true) {
          const { done, value } = await reader.read();
          if (done) break;

          buffer += decoder.decode(value, { stream: true });
          const lines = buffer.split("\n");
          buffer = lines.pop(); // keep incomplete line in buffer

          for (const line of lines) {
            if (!line.startsWith("data: ")) continue;
            const data = line.slice(6).trim();
            if (data === "[DONE]") break;

            try {
              const parsed = JSON.parse(data);
              if (parsed.content) {
                // Stream each chunk into the assistant message
                setMessages((prev) =>
                  prev.map((m) =>
                    m.id === assistantId
                      ? { ...m, content: m.content + parsed.content }
                      : m
                  )
                );
              }
              if (parsed.error) throw new Error(parsed.error);
            } catch (e) {
              if (e.message !== "Unexpected end of JSON input") {
                throw e;
              }
            }
          }
        }
      } catch (err) {
        console.error("Chat error:", err);
        setMessages((prev) =>
          prev.map((m) =>
            m.id === assistantId
              ? {
                  ...m,
                  content: "Something went wrong. Please try again.",
                  error: true,
                }
              : m
          )
        );
      } finally {
        setIsLoading(false);
      }
    },
    [input, isLoading]
  );

  const handleKeyDown = (e) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  const clearChat = async () => {
    setMessages([]);
    await fetch(`${BACKEND_URL}/api/chat/${CONVERSATION_ID}`, {
      method: "DELETE",
    }).catch(() => {});
  };

  return (
    <div className="chat-wrapper">
      {/* ── Header ── */}
      <header className="chat-header">
        <div className="header-left">
          <div className="avatar">🤖</div>
          <div className="header-info">
            <h1>AI Assistant</h1>
            <span className="status">Online · GPT-4o</span>
          </div>
        </div>
        {messages.length > 0 && (
          <button className="clear-btn" onClick={clearChat}>
            Clear chat
          </button>
        )}
      </header>

      {/* ── Messages ── */}
      <main className="messages-area">
        {messages.length === 0 && (
          <div className="welcome-message">
            <h2>How can I help you?</h2>
            <p>Ask me anything — I'll remember our conversation.</p>
            <div className="suggestions">
              {SUGGESTIONS.map((s) => (
                <button
                  key={s}
                  className="suggestion-btn"
                  onClick={() => sendMessage(s)}
                >
                  {s}
                </button>
              ))}
            </div>
          </div>
        )}

        {messages.map((msg) => (
          <div key={msg.id} className={`message ${msg.role}`}>
            <div className="msg-avatar">
              {msg.role === "user" ? "👤" : "🤖"}
            </div>
            <div className={`bubble ${msg.error ? "error-bubble" : ""}`}>
              {msg.role === "assistant" ? (
                msg.content === "" && !msg.error ? (
                  <div className="typing-indicator">
                    <span /><span /><span />
                  </div>
                ) : (
                  <ReactMarkdown>{msg.content}</ReactMarkdown>
                )
              ) : (
                msg.content
              )}
            </div>
          </div>
        ))}

        <div ref={messagesEndRef} />
      </main>

      {/* ── Input ── */}
      <footer className="input-area">
        <div className="input-row">
          <textarea
            ref={textareaRef}
            value={input}
            onChange={handleInputChange}
            onKeyDown={handleKeyDown}
            placeholder="Message AI assistant… (Enter to send, Shift+Enter for new line)"
            rows={1}
            disabled={isLoading}
          />
          <button
            className="send-btn"
            onClick={() => sendMessage()}
            disabled={isLoading || !input.trim()}
            aria-label="Send message"
          >
            {isLoading ? "⏳" : "➤"}
          </button>
        </div>
        <p className="input-hint">
          AI can make mistakes — verify important information.
        </p>
      </footer>
    </div>
  );
}

export default App;
